// InsightPanel.jsx — Displays 6-type insights per chart

import { useState } from "react";

const INSIGHT_TYPES = [
  { key: "descriptive", label: "Descriptive", icon: "📊", color: "#4f8ef7", desc: "What happened" },
  { key: "diagnostic",  label: "Diagnostic",  icon: "🔍", color: "#7c5cfc", desc: "Why it happened" },
  { key: "predictive",  label: "Predictive",  icon: "📈", color: "#00d4aa", desc: "What's next" },
  { key: "prescriptive",label: "Prescriptive",icon: "💡", color: "#f7a84f", desc: "What to do" },
  { key: "evaluative",  label: "Evaluative",  icon: "✅", color: "#4ff79a", desc: "Data quality" },
  { key: "exploratory", label: "Exploratory", icon: "🔭", color: "#e879f9", desc: "Hidden patterns" },
];

export default function InsightPanel({ insights, summary }) {
  const [activeKpi, setActiveKpi] = useState(insights?.[0]?.kpi || "");
  const [activeType, setActiveType] = useState("descriptive");

  const current = insights?.find((i) => i.kpi === activeKpi);

  return (
    <div style={styles.panel}>
      <div style={styles.panelHeader}>
        <div style={styles.panelTitleRow}>
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <circle cx="8" cy="8" r="7" stroke="#7c5cfc" strokeWidth="1.3"/>
            <path d="M5 8l2 2 4-4" stroke="#7c5cfc" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
          <span style={styles.panelTitle}>AI Insights</span>
        </div>
      </div>

      {/* Summary */}
      {summary && (
        <div style={styles.summaryBox}>
          <div style={styles.summaryLabel}>
            <span>⚡</span> Executive Summary
          </div>
          <p style={styles.summaryText}>{summary}</p>
        </div>
      )}

      {/* KPI selector */}
      <div style={styles.kpiScroll}>
        {insights?.map((ins) => (
          <button
            key={ins.kpi}
            style={{ ...styles.kpiBtn, ...(activeKpi === ins.kpi ? styles.kpiBtnActive : {}) }}
            onClick={() => setActiveKpi(ins.kpi)}
          >
            {ins.kpi}
          </button>
        ))}
      </div>

      {/* Insight type tabs */}
      {current && (
        <>
          <div style={styles.typeTabs}>
            {INSIGHT_TYPES.map((t) => (
              <button
                key={t.key}
                style={{
                  ...styles.typeTab,
                  ...(activeType === t.key ? { ...styles.typeTabActive, borderColor: t.color, color: t.color } : {})
                }}
                onClick={() => setActiveType(t.key)}
                title={t.desc}
              >
                <span>{t.icon}</span>
                <span style={styles.typeLabel}>{t.label}</span>
              </button>
            ))}
          </div>

          {/* Insight content */}
          {INSIGHT_TYPES.map((t) =>
            activeType === t.key ? (
              <div key={t.key} style={styles.insightBox} className="fade-in">
                <div style={{ ...styles.insightHeader, color: t.color }}>
                  <span style={styles.insightIcon}>{t.icon}</span>
                  <div>
                    <div style={styles.insightType}>{t.label}</div>
                    <div style={styles.insightDesc}>{t.desc}</div>
                  </div>
                </div>
                <p style={styles.insightText}>{current[t.key]}</p>
              </div>
            ) : null
          )}
        </>
      )}
    </div>
  );
}

const styles = {
  panel: {
    background: "var(--bg2)",
    border: "1px solid var(--border)",
    borderRadius: "var(--radius-lg)",
    overflow: "hidden",
  },
  panelHeader: {
    padding: "16px 20px",
    borderBottom: "1px solid var(--border)",
  },
  panelTitleRow: { display: "flex", alignItems: "center", gap: "8px" },
  panelTitle: { fontSize: "13px", fontWeight: 700, color: "var(--text2)", textTransform: "uppercase", letterSpacing: "0.07em" },
  summaryBox: {
    margin: "16px 16px 0",
    padding: "14px 16px",
    background: "rgba(124,92,252,0.08)",
    border: "1px solid rgba(124,92,252,0.2)",
    borderRadius: "var(--radius)",
  },
  summaryLabel: {
    display: "flex", alignItems: "center", gap: "6px",
    fontSize: "11px", fontWeight: 700, color: "#a78bfa",
    textTransform: "uppercase", letterSpacing: "0.07em", marginBottom: "8px",
  },
  summaryText: { fontSize: "13px", color: "var(--text)", lineHeight: 1.7 },
  kpiScroll: {
    display: "flex", flexWrap: "wrap", gap: "8px",
    padding: "16px",
  },
  kpiBtn: {
    padding: "6px 12px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "20px", color: "var(--text2)",
    fontSize: "12px", cursor: "pointer", transition: "all 0.15s",
  },
  kpiBtnActive: {
    background: "rgba(79,142,247,0.15)",
    border: "1px solid var(--accent)", color: "var(--accent)",
  },
  typeTabs: {
    display: "flex", flexWrap: "wrap", gap: "6px",
    padding: "0 16px 16px",
  },
  typeTab: {
    display: "flex", alignItems: "center", gap: "5px",
    padding: "6px 10px",
    background: "var(--bg3)", border: "1px solid var(--border)",
    borderRadius: "8px", color: "var(--text3)",
    fontSize: "12px", cursor: "pointer", transition: "all 0.15s",
  },
  typeTabActive: { background: "rgba(79,142,247,0.1)" },
  typeLabel: { fontWeight: 500 },
  insightBox: {
    margin: "0 16px 16px",
    padding: "16px",
    background: "var(--bg3)",
    border: "1px solid var(--border)",
    borderRadius: "var(--radius)",
  },
  insightHeader: {
    display: "flex", alignItems: "flex-start", gap: "12px",
    marginBottom: "12px",
  },
  insightIcon: { fontSize: "20px", lineHeight: 1 },
  insightType: { fontSize: "13px", fontWeight: 700, marginBottom: "2px" },
  insightDesc: { fontSize: "11px", color: "var(--text3)" },
  insightText: { fontSize: "14px", color: "var(--text)", lineHeight: 1.7 },
};
